mapper.select:
SELECT id, question, question_norm, top_similarity, best_faq_id, embedding, created_at
  FROM chatbot_unanswered_question
 WHERE status = #{status}
   AND created_at >= #{from}
   AND created_at < #{toExclusive}
 ORDER BY created_at DESC, id DESC

SELECT DATE(created_at) AS `date`, COUNT(DISTINCT question_norm) AS `count`
  FROM chatbot_unanswered_question
 WHERE status = #{status}
   AND created_at >= #{from}
   AND created_at < #{toExclusive}
 GROUP BY DATE(created_at)
 ORDER BY `date`
